function BaseProcess:sortPlayers(players)
    table.sort(players, function(p1, p2)
        if p1.kills ~= p2.kills then
            return p1.kills > p2.kills
        end
        return p1.userId < p2.userId
    end)
end

function BaseProcess:isGameOver(player)
