function BaseProcess:buildShowName(player, same)
    local nameList = {}

    local disName = player.name
    if player:isGameVip() then
        if BaseMain:isChina() then
            disName = TextFormat.colorGold .. "[会员]" .. disName
        else
            disName = TextFormat.colorGold .. "[VIP]" .. disName
        end
    end
    PlayerIdentityCache:buildNameList(player.userId, nameList, disName)
    return table.concat(nameList, "\n")
end

function BaseProcess:isGameBegin()
